window.__QUIZ_DATA__=[{"id":"theory>Geography>1994>1>a","subject":"Geography","year":"1994","type":"Theory","sub_label":"a","group":"","topic":"REGIONAL GEOGRAPHY OF NIGERIA : POPULATION","question":"Explain the term migration and describe any three forms it may take","images":[],"marking_scheme":"Migration is the movement of people from one geographical area tc another involving permanent or temporary settlement.  Three forms of migration are:    (i) Rural-Urban migration    (ii) Urban-Rural migration    (iii) Urban-Urban migration","marks":"1","difficulty":"2"},{"id":"theory>Geography>1994>1>b","subject":"Geography","year":"1994","type":"Theory","sub_label":"b","group":"","topic":"REGIONAL GEOGRAPHY OF NIGERIA : POPULATION","question":"State any four factors that may be responsible for migration","images":[],"marking_scheme":"(i) Physical conditions like climate, relief, etc    (ii) Natural disasters like famine, floods, etc    (iii) Insecurity e.g war    (iv) Differences in the availability of social amenities","marks":"1","difficulty":"2"},{"id":"theory>Geography>1994>1>c","subject":"Geography","year":"1994","type":"Theory","sub_label":"c","group":"","topic":"REGIONAL GEOGRAPHY OF NIGERIA : POPULATION","question":"Outline any three advantages and three disadvantages of any one type of migration mentioned in (a) above.","images":[],"marking_scheme":"Three advantages or Rural-Urban Migration:    (i) reduced population pressure on agricultural lands    (ii) Supply of migrant labour    (iii) Promotion of cultural integration.    Three disadvantages of Rural-Urban Migration:    (i) It leads to unemployment    (ii) It leads to high cost of living    (iii) There is pressure on social amenities.","marks":"1","difficulty":"3"},{"id":"theory>Geography>1994>2>a","subject":"Geography","year":"1994","type":"Theory","sub_label":"a","group":"","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"Explain four factors that may affect the growth of settleements.","images":[],"marking_scheme":"Four Factors that may affect the Growth of Settlements:-    1. Unfavourable Climate:- Areas with unfavourable climate e.g. hot temperature and excessive rainfall will definately make living condition difficult for people and this repels people thereby affecting the growth of the settlement.    ii. Lack of Social Amenities:- When basic amenities like roads, pipe borne water, electricity etc, are lacking, the growth of that settlement would be hindered because these are some of the things that will attract people to the area.    iii. Lack of natural resources:- Where there is lack of natural resources like minerals in an area or when there is availability of natural resources but they remain untapped, people would definately not be attracted to such area.    iv. Lack of fertile soils:- A place which lacks fertile soil would not attract people who mostly are looking for fertile soils to cultivate their crops hence growth of the area is affected.","marks":"1","difficulty":"2"},{"id":"theory>Geography>1994>2>b","subject":"Geography","year":"1994","type":"Theory","sub_label":"b","group":"","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"Describe any four effects of an increase in tthe population ssize of settlements","images":[],"marking_scheme":"Effects of an increase in population size of settlements:-Unemployment or under employment:- Settlements with a high population size usually cannot provide jobs' for the increasing influx of people to the area. This leads to unemployment and underemployment.    Inadequate housing:- Since the population size of the    settlement increases it may get to a stage or point when the number of houses around will not be able to accommodate the increase in population.    Increase in size of market:- The size of market in the settlement in question in expanded because there will be more demand for various commodities.    Pressure on social amenities:- Social amenities like pipe borne water, electricity etc. are usually over stressed by the increase in population.","marks":"1","difficulty":"2"},{"id":"theory>Geography>1994>3","subject":"Geography","year":"1994","type":"Theory","sub_label":"3","group":"","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRANSPORTATION","question":"Highlight the relative contributions of roads and railways to national development in any country of your choice","images":[],"marking_scheme":"(i) Increased agricultural,mineral and industrial production    (ii) It aids the movement of people from one place to another    (iii) It links areas of production with areas of consumption    (iv) It leads to increased trade between towns    (v) It generates revenue    (vi) It leads to diffusion of ideas and innovations    (vii) It promotes employment opportunities.","marks":"1","difficulty":"2"},{"id":"theory>Geography>1994>4>a","subject":"Geography","year":"1994","type":"Theory","sub_label":"a","group":"","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"Explain the term manufacturing industry","images":[],"marking_scheme":"Manufacturing industry involves the turning of raw materials into new products by mechanical or chemical processes at home or in the factory.","marks":"1","difficulty":"1"},{"id":"theory>Geography>1994>4>b","subject":"Geography","year":"1994","type":"Theory","sub_label":"b","group":"","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"Highlight the characteristic features of manufacturing industries in Tropical African countries","images":[],"marking_scheme":"(i) Importation of skilled labour    (ii) Imported raw materials    (iii)They are labour intensive    (iv) They are largely small-scaled    (v) The industries are concentrated in few locations","marks":"1","difficulty":"2"},{"id":"theory>Geography>1994>4>c","subject":"Geography","year":"1994","type":"Theory","sub_label":"c","group":"","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"Give any four reasons why countries embark on industrialization","images":[],"marking_scheme":"(i) To reduce over dependence on imported goods    (ii) It acts as a source of revenue    (iii) To generate employment    (iv) To improve the standard of living.","marks":"1","difficulty":"2"},{"id":"theory>Geography>1994>5","subject":"Geography","year":"1994","type":"Theory","sub_label":"5","group":"","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRADE","question":"Compare and contrast the trade relations between Nigeria and the United Kingdom with that between Nigeria and Japan","images":[],"marking_scheme":"Similarities:  (i) There is importation of finished products from both countries    (ii) There is export of primary products to both countries    (iii) There is importation of skilled labour from both countries    (iv) There is importation of technology from both countries.    Differences:  (i) There is older trade relationship with U.K than Japan    (ii) There is greater volume of trade with the U.K    (iii) Exportation of crude oil to Japan and none to U.K    (iv) Importation of finished goods to Nigeria from Japan than U.K","marks":"1","difficulty":"3"},{"id":"theory>Geography>1994>6","subject":"Geography","year":"1994","type":"Theory","sub_label":"6","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"The table below gives the climatic data for two different stations A & B, in Nigeria. Use the data to answer the questions that follow   stationAltitudeLatitudeJFMAMJJASONDA360m13\u00baNRainfall (cm)0.00.00.01.04.89.115.524.914.51.51.50.0Temperature (\u00baC)242832333229272628312926B225m7\u00baNRainfall (cm)1.02.38.913.713.78.816.08.417.815.54.61.0Temperature (\u00baC)272929282726242325252627  (i) Identify the climatic belt to which each station belongs  (ii) Outline the main climatic characteristics of each station  (iii) In what ways will the agricultural practices in the two stations differ?","images":[],"marking_scheme":"(i) Station: A belongs to the tropical continental (or Sudan) climate while station B belongs to the sub-equatorial climate    (ii) Main climatic characteristics of station A:    (a)It has a high temperature throughout the year    (b) The maximum temperature is 33\u00b0C while the minimum is 24\u00b0C    (c) Annual temperature range is 9\u00b0C    (d) Rainfall is seasonal.    Main climatic characteristics of station B:    (a) The temperature is high throughout the year    (b) Maximum temperature is 29\u00b0C while the minimum is 23\u00b0C    (c) The annual range of temperature is 6\u00b0C    (d) It has a double maxima    (iii) Ways in which agricultural practices in the two stations differ include    (a) Rainfall is used throughout the year in station B while irrigation is used in station A    (b) Cereals are mainly cultivated in station Awhile tree crops are cultivated in station B    (C) Animal rearing is common in station A than in station B    (d) Double cropping is done in station Awhile single cropping is done in station B","marks":"1","difficulty":"3"},{"id":"theory>Geography>1994>7>a","subject":"Geography","year":"1994","type":"Theory","sub_label":"a","group":"","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRADE","question":"On an outline map of Nigeria locate and name  (i) the source areas and the destinations of two named major items of internal trade, indicate by an arrow the direction of movement of each commodity. (ii) one important town in each area","images":["data:image/png;base64,"],"marking_scheme":"","marks":"1","difficulty":"2"},{"id":"theory>Geography>1994>7>b","subject":"Geography","year":"1994","type":"Theory","sub_label":"b","group":"","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRADE","question":"Outline four factors that have favoured the development of internal trade in Nigeria","images":[],"marking_scheme":"(i) Wide demand for such goods    (ii) Good transportation network    (iii) Favourable climate for the cultivation of the crops    (iv) Differences in products","marks":"1","difficulty":"2"},{"id":"theory>Geography>1994>8>a","subject":"Geography","year":"1994","type":"Theory","sub_label":"a","group":"","topic":"REGIONAL GEOGRAPHY OF NIGERIA : RESOURCES","question":"On a sketch map of Nigeria, locate and name  (i) one area important for the mining of each of limestone, tin, crude oil and coal  (ii) one major town in each area","images":["data:image/jpeg;base64,","data:image/png;base64,"],"marking_scheme":"","marks":"1","difficulty":"2"},{"id":"theory>Geography>1994>8>b","subject":"Geography","year":"1994","type":"Theory","sub_label":"b","group":"","topic":"REGIONAL GEOGRAPHY OF NIGERIA : RESOURCES","question":"Explain the importance of any one of the minerals to the economy of Nigeria","images":[],"marking_scheme":"(i) Crude oil provides essential products like petrol and kerosine    (ii) It provides employment to Nigerians    (iii) It also provides raw materials for industries    (iv) It provides foreign exchange for the nation    (v) Provision of infrastructure like pipe borne water, good roads, electricity, etc","marks":"1","difficulty":"2"},{"id":"theory>Geography>1994>8>c","subject":"Geography","year":"1994","type":"Theory","sub_label":"c","group":"","topic":"REGIONAL GEOGRAPHY OF NIGERIA : INDUSTRY","question":"Outline any four problems facing the mining industry in Nigeria.","images":[],"marking_scheme":"(i) Environmental pollution    (ii) It leads to loss of farmlands    (iii) Lack of skilled labour    (iv) Inadequate transport facilities","marks":"1","difficulty":"2"},{"id":"theory>Geography>1994>9>a","subject":"Geography","year":"1994","type":"Theory","sub_label":"a","group":"","topic":"REGIONAL GEOGRAPHY OF NIGERIA : ISSUES ON DEVELOPMENT AND ENVIRONMENTAL CONCERNS","question":"Identify any five problems of development in the Niger Delta region","images":[],"marking_scheme":"(i) Problem of soil erosion to environment    (ii) Oil pollution and oil spillage are major problems    (iii) High level of salt inhibits agriculture    (iv) There is poor water transportation development    (v) It has a very low population.","marks":"1","difficulty":"2"},{"id":"theory>Geography>1994>9>b","subject":"Geography","year":"1994","type":"Theory","sub_label":"b","group":"","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"How can the problems be solved?","images":[],"marking_scheme":"(i) Floods and erosion should be controlled    (ii) Adequate care should be taken to avoid oil spillage on water    (iii) The land should be reclaimed from marshy areas    (iv) Flyovers should be constructed    (iv) Provision of basic amenities for the people","marks":"1","difficulty":"1"},{"id":"theory>Geography>1994>10>a","subject":"Geography","year":"1994","type":"Theory","sub_label":"a","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Draw a sketch map of Nigeria to show  (i) the home areas of the following people: Fulani, lbibio, Yoruba and Urhobo  (ii) one major town in each home area","images":["data:image/jpeg;base64,"],"marking_scheme":"","marks":"1","difficulty":"3"},{"id":"theory>Geography>1994>10>b","subject":"Geography","year":"1994","type":"Theory","sub_label":"b","group":"","topic":"REGIONAL GEOGRAPHY OF AFRICA : SELECTED TOPICS","question":"Select any two of these peoples and explain the effects of the physical environment on their occupation and types of house","images":[],"marking_scheme":"YORUBA: The effects of the physical environment and type of house in Yoruba land are:    (i) Yorubas are mainly involved in farming, weaving, carving, etc.  - Their houses are made of mud.  - Thatched houses and modern buildings are also seen in urban areas    (ii) FULANI: The effects of the physical environment and type of house in Fulani are :  (i) Fulanis are mainly involved in cattle rearing, farming and trading  (ii) Their houses are made of mobile tents made of grass and leaves, no permanent shelter or houses","marks":"1","difficulty":"2"},{"id":"theory>Geography>1994>11>a","subject":"Geography","year":"1994","type":"Theory","sub_label":"a","group":"","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"Outline any five factors responsible for the low density of population in some parts of West Africa","images":[],"marking_scheme":"(i) Historical factors like war and slavery    (ii) Unfavourable climate in Northern part of West Africa    (iii) Problems of pests and diseases    (iv) Presence of relief, e.g eastern highlands    (v) Lack of mineral resources and social amenities","marks":"1","difficulty":"2"},{"id":"theory>Geography>1994>11>b","subject":"Geography","year":"1994","type":"Theory","sub_label":"b","group":"","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"In what four ways can low population density be an advantage?","images":[],"marking_scheme":"(i) It leads to high standard of living    (ii) Adequate food supply    (iii) Low pressure on social amenities    (iv) Low crime rate","marks":"1","difficulty":"2"},{"id":"theory>Geography>1994>12>a","subject":"Geography","year":"1994","type":"Theory","sub_label":"a","group":"","topic":"REGIONAL GEOGRAPHY OF AFRICA : AGRICULTURE","question":"Describe any five distinguishing features of plantation agriculture in East Africa","images":[],"marking_scheme":"(i) It involves the growing of one crop on the same piece of land    (ii) A large area of land in required    (iii) It requires high capital investment    (iv) Cash crops are mainly involved    (v)All farm operations are mechanized","marks":"1","difficulty":"2"},{"id":"theory>Geography>1994>12>b","subject":"Geography","year":"1994","type":"Theory","sub_label":"b","group":"","topic":"REGIONAL GEOGRAPHY OF AFRICA : AGRICULTURE","question":"Identify five factors which have favoured the practice of plantation agriculture in East Africa","images":[],"marking_scheme":"(i) Favourable climate  (ii) Rich fertile soils  (iii) High demands for crops (market)  (iv) Availability of cheap labour  (v) Good transportation system","marks":"1","difficulty":"2"},{"id":"theory>Geography>1994>13>a","subject":"Geography","year":"1994","type":"Theory","sub_label":"a","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"On an outline map of Africa, locate and name  (i) two land-locked countries  (ii) two ports, each in a different country, serving these land-locked countries  (iii) the countries in which these ports are located","images":["data:image/png;base64,"],"marking_scheme":"","marks":"1","difficulty":"3"},{"id":"theory>Geography>1994>13>b","subject":"Geography","year":"1994","type":"Theory","sub_label":"b","group":"","topic":"REGIONAL GEOGRAPHY OF AFRICA : SELECTED TOPICS","question":"What four major problems are facing land-locked countries in Africa?","images":[],"marking_scheme":"(i) There is economic dependence on other countries    (ii) There is loss of revenue due to smuggling    (iii) There is also the problem of political insecurity    (iv) There is high cost of freight rate","marks":"1","difficulty":"2"},{"id":"theory>Geography>1994>14>a","subject":"Geography","year":"1994","type":"Theory","sub_label":"a","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"On a map of Africa, locate and name:  (i) three rivers on which hydro-electric power is generated  (ii) the hydroelectric power station on each river","images":["data:image/png;base64,"],"marking_scheme":"","marks":"1","difficulty":"2"},{"id":"theory>Geography>1994>14>b","subject":"Geography","year":"1994","type":"Theory","sub_label":"b","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL RESOURCES","question":"Examine three factors that favour the generation of hydro-electric power in Africa","images":[],"marking_scheme":"(i) A good relief and presence of waterfalls  (ii) Abundance of rainfall  (iii) There must be high volume of water in rivers  Heavy Rainfall:- Most parts of Africa lie within the tropics and experience heavy rainfall during major part of the year,    Steep Slope:- Africa has many plateau surfaces. These make the rivers to flow with great speed and descend from steep gradients. Waterfalls formed on such steep slopes provide excellent conditions for the generation of hydro electric power.    Existence of lakes:- The existence of natural or artificial    lakes help to hold water for use during the periods of low rainfall and thus help to maintain a continuity in power generation.    Market:- There is a good domestic and industrial markets this has made the project profitable and hence favoured its generation.","marks":"1","difficulty":"2"},{"id":"theory>Geography>1994>14>c","subject":"Geography","year":"1994","type":"Theory","sub_label":"c","group":"","topic":"REGIONAL GEOGRAPHY OF AFRICA : SELECTED TOPICS","question":"Of what importance are hydro-electric power projects to Tropical African countries?","images":[],"marking_scheme":"Hydro-electric power projects are of significant importance to Tropical African countries for several reasons. Firstly, they provide a renewable source of energy that is crucial for the economic development of these nations. Many Tropical African countries face energy shortages, which hinder industrial growth and limit access to electricity for households. By harnessing the power of rivers and waterfalls, hydro-electric projects can generate substantial amounts of electricity, which can be used to power industries, schools, and homes, thereby improving the quality of life for millions of people.    Secondly, hydro-electric power projects contribute to environmental sustainability. Unlike fossil fuels, hydro-electric power does not emit greenhouse gases during operation, making it a cleaner alternative that helps combat climate change. This is particularly important for Tropical African countries, which are often more vulnerable to the impacts of climate change, such as droughts and floods.    Additionally, these projects can stimulate local economies by creating jobs during the construction and maintenance phases. They can also lead to the development of infrastructure, such as roads and bridges, which can benefit local communities beyond just energy production.    Moreover, hydro-electric power can enhance energy security for Tropical African countries. By diversifying their energy sources and reducing dependence on imported fossil fuels, these nations can achieve greater energy independence and stability.    In conclusion, hydro-electric power projects are vital for the economic, environmental, and social development of Tropical African countries. They provide a sustainable energy source, promote job creation, and enhance energy security, making them an essential component of the region's development strategy.","marks":"1","difficulty":"2"},{"id":"theory>Geography>1994>15>a","subject":"Geography","year":"1994","type":"Theory","sub_label":"a","group":"","topic":"REGIONAL GEOGRAPHY OF NIGERIA : ECOWAS","question":"Outline any four objectives of the ECOWAS","images":[],"marking_scheme":"Removal of restrictions on trade among member states.    Elimination of custom duties and other charges in respect of the importation and exportation of goods between member states    The establishment of similar agricultural policies and the encouragement and pursuit of common projects in the member states agro industrial enterprises.    Abolition of obstacles to free movement of people across member states boundaries.","marks":"1","difficulty":"2"},{"id":"theory>Geography>1994>15>b","subject":"Geography","year":"1994","type":"Theory","sub_label":"b","group":"","topic":"REGIONAL GEOGRAPHY OF NIGERIA : ECOWAS","question":"State any five problems that have limited the achievement of these objectives","images":[],"marking_scheme":"Three Problems that have limited the achievements of ECOWAS's Objectives:-    Most of the member countries depend heavily on revenue from tariffs, and so the abolition or reduction of tariffs among member countries will lead to loss of income to these countries.    Sorne member countries do not pay their dues regularly leading to shortage of funds.    Differences in currency limits the level of trade among member states.","marks":"1","difficulty":"2"},{"id":"theory>Geography>1994>15>c","subject":"Geography","year":"1994","type":"Theory","sub_label":"c","group":"","topic":"REGIONAL GEOGRAPHY OF NIGERIA : ECOWAS","question":"Suggest any three ways of solving these problems.","images":[],"marking_scheme":"Agreed resolution and programmes should be implemented.  Members should pay their dues promptly  Common currency should be adopted to facilitate trade within the region.","marks":"1","difficulty":"2"}];